import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';

import movie from '../Assets/movie.png';
import workout from '../Assets/workout.png';
import commandLine from '../Assets/commandLine.png';

const BoxWithHover = styled(Box)`
  transition: 0.5s;
  &:hover {
    transform: scale(1.05); /* Enlarge the image on hover */
  }
`;

const ProjectItemContainer = styled(Container)`
  display: flex;
  align-items: center;
  width: 100%;
  margin: auto;
  margin-bottom: 25vh;
  cursor: pointer;
`;

const ProjectImage = styled.img`
  height: 10vw;
  margin-right: 2;
`;

const ProjectName = styled(Typography)`
  display: inline-block;
`;

const projectItem = (image, name, func) => {
  return (
    <ProjectItemContainer
      maxWidth="none"
      onClick={func}
    >
      <BoxWithHover>
        <ProjectImage src={image} alt={`${name} logo`} />
      </BoxWithHover>
      <ProjectName variant="h3">{name}</ProjectName>
    </ProjectItemContainer>
  );
};

function Projects() {
  const navigate = useNavigate();
  const reroute = (path) => {
    return () => navigate(path);
    // return () => window.open(path, '_blank');
  };

  return (
    <Container
      maxWidth="none"
      sx={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        width: '100%',
        mx: 'auto',
        mb: '25vh'
      }}
    >
      <Typography id="projects" variant="h2" my={4}>
        Projects
      </Typography>
      <Box sx={{ display: 'flex', flexDirection: { xs: 'column', sm: 'row' }, justifyContent: 'center' }}>
        {projectItem(movie, 'Topher Emby', reroute('/TopherEmby'))}
        {projectItem(commandLine, 'OnlyKyles', reroute('/OnlyKyles'))}
        {projectItem(workout, 'Flat & Iron Abs', reroute('/FlatIronAbs'))}
      </Box>
    </Container>
  );
}

export default Projects;
